//==============================================================================
// 文件：src/vendor/cgltf.cpp
// 模块定位：第三方 cgltf 单文件实现入口，使 glTF 解析函数在本项目中拥有链接实体。
// 数据流：输入是 cgltf 头文件的实现宏；输出是可被 scene_gltf.cpp 调用的解析函数实现。
// 方法说明：单文件库通常通过一个翻译单元定义 implementation 宏，本文件隔离该约定以避免重复定义。
// 正确性约束：同一工程只能有一个 CGLTF_IMPLEMENTATION 翻译单元；不要在这里加入项目业务逻辑。
// 注释风格：使用中文解释 CPU 侧语义；保留必要的 API、类型名和数学缩写以便检索。
//==============================================================================
// 宏配置说明：定义编译期常量或功能开关，让 CPU 与 GPU 按同一套布局和路径工作。
// 宏值通常会影响 buffer 大小、工作组规模或条件编译分支，修改后需要同时检查 C++ 和着色器侧。
#define _CRT_SECURE_NO_WARNINGS


// 宏配置说明：定义编译期常量或功能开关，让 CPU 与 GPU 按同一套布局和路径工作。
// 宏值通常会影响 buffer 大小、工作组规模或条件编译分支，修改后需要同时检查 C++ 和着色器侧。
#define CGLTF_IMPLEMENTATION
#if !defined(NDEBUG)


// 宏配置说明：定义编译期常量或功能开关，让 CPU 与 GPU 按同一套布局和路径工作。
// 宏值通常会影响 buffer 大小、工作组规模或条件编译分支，修改后需要同时检查 C++ 和着色器侧。
#define CGLTF_VALIDATE_ENABLE_ASSERTS 1
#endif


// 依赖说明：引入本编译单元需要的外部库、项目模块和共享着色器布局。
// 依赖顺序通常反映抽象层次：先外部库，再项目模块，最后与 GPU 共享的接口定义。
#include <cgltf.h>
